UPDATE SFCTE
SET status = '已检验'
WHERE RTRIM(TE001)+'-'+RTRIM(TE002)+'-'+RTRIM(TE023)+'-'+'1'+'-'+RTRIM(TE008) = #{code}

UPDATE SFCTE
SET status = '已取消'
WHERE RTRIM(TE001)+'-'+RTRIM(TE002)+'-'+RTRIM(TE023)+'-'+'1'+'-'+RTRIM(TE008) = #{code}

mapper.select:
WITH Results AS ( SELECT s.MO_ROUTING_D_ID,s.TA001,s.TA002,s.TA003,s.TA004,s.TA005,m.TA029,m.TA064,m.TA006,m.TA034,m.TA035,m.TA003 AS kgtime,m.TA015 AS TA015 ,m.TA011,m.TA007,s.TA007 AS gz,m.TA027, (SELECT ISNULL(MIN(TE011), 0) num FROM (SELECT SUM(TE011) TE011 FROM SFCTE WHERE TE006 = s.TA001 AND TE007 = s.TA002 AND TE008 = s.TA003 GROUP BY UDF09) A) AS num, (SELECT MW002 FROM CMSMW WHERE MW001 = s.TA004) AS name FROM SFCTA AS s LEFT JOIN MOCTA m ON s.TA001 = m.TA001 AND s.TA002 = m.TA002 WHERE m.TA011!='Y' AND m.TA011 != 'y'
AND s.TA001 = #{single}
AND s.TA002 = #{odd}
AND m.TA006 LIKE '%'+#{ph}+'%'
AND m.TA034 LIKE '%'+#{pm}+'%'
AND s.TA004 LIKE '%'+#{gy}+'%'
)SELECT * FROM Results WHERE TA015 > num

SELECT *
FROM (
SELECT ROW_NUMBER() OVER (ORDER BY CREATE_DATE DESC) AS RowNum, CREATE_DATE, TE006, TE007, TE011, UDF51, UDF52, UDF53, TE017, TE018, TE019, UDF06 ,TE020
FROM SFCTE


        AND UDF06 LIKE '%'+#{UDF06}+'%'


        AND CREATE_DATE BETWEEN #{start_time} AND #{end_time}


) AS t
WHERE t.RowNum BETWEEN (#{page}-1) * #{pageSize} + 1 AND (#{page}-1) * #{pageSize} + #{pageSize}

SELECT COUNT(*) FROM SFCTE
AND UDF06 LIKE '%'+#{UDF06}+'%'
AND CREATE_DATE BETWEEN #{start_time} AND #{end_time}

SELECT *
FROM (
SELECT ROW_NUMBER() OVER (ORDER BY CREATE_DATE DESC) AS RowNum, CREATE_DATE, TE006, TE007, TE011, UDF51, UDF52, UDF53, TE017, TE018, TE019, UDF06 ,TE020
FROM SFCTE


        AND UDF06 = #{UDF06}


        AND (UDF06 = '一次测温' OR UDF06 = '三次测温')


        AND CREATE_DATE BETWEEN #{start_time} AND #{end_time}


) AS t
WHERE t.RowNum BETWEEN (#{page}-1) * #{pageSize} + 1 AND (#{page}-1) * #{pageSize} + #{pageSize}

SELECT COUNT(*)
FROM SFCTE


        AND UDF06 = #{UDF06}


        AND (UDF06 = '一次测温' OR UDF06 = '三次测温')


        AND CREATE_DATE BETWEEN #{start_time} AND #{end_time}

SELECT SFCTE.*, ISNULL(c.number, 0) AS num, number*100/SFCTE.UDF57 AS jindu, ISNULL(SFCTE.UDF57 - ISNULL(c.number, 0), 0) AS yunxu FROM SFCTE --LEFT JOIN CMSMW MW ON MW.MW001 = SFCTE.TE009 LEFT JOIN ( SELECT (SUM(UDF51)+SUM(UDF52)+SUM(UDF53)+SUM(TE011)) AS number,(UDF09+'-'+UDF10+'-'+UDF11) AS bbb FROM SFCTE WHERE TE001 = 'D410' GROUP BY (UDF09+'-'+UDF10+'-'+UDF11) ) as c ON c.bbb = SFCTE.TE001 + '-' + SFCTE.TE002 + '-' + SFCTE.TE003
SFCTE.TE001 = 'D420' AND SFCTE.UDF57 > ISNULL(c.number, 0) --AND SFCTE.UDF09 != 'N' AND MW.MW004 = '1'
AND SFCTE.TE004 = #{employeeNumber}
AND SFCTE.TE002 = #{odd}
AND SFCTE.TE003 = #{xh}
AND SFCTE.TE017 LIKE CONCAT('%', #{TE017}, '%')
AND SUBSTRING(SFCTE.CREATE_DATE, 1, 8) >= #{beginTime}
AND #{endTime} >= SUBSTRING(SFCTE.CREATE_DATE, 1, 8)
order by SFCTE.CREATE_DATE DESC

SELECT TE001,TE002,TE003,TE004,TE011,UDF53,UDF51,UDF52,UDF02,UDF03,UDF04,TE015,LTRIM(RTRIM(CREATE_DATE)) CREATE_DATE,TE023, TE017 itemNo,TE018 itemName,TE019 itemSpec,TE008 gxNo,UDF01 gxName FROM SFCTE
TE023 >= #{beginTime}
AND #{endTime} >= TE023
AND TE001 = #{single} AND TE004 = #{userId}
ORDER BY CREATE_DATE DESC

SELECT  SUBSTRING(CREATE_DATE, 1, 8) date,SUM(TE011)+SUM(UDF53) num
FROM SFCTE

TE001 = 'D410' AND TE004 = #{userId}

    AND SUBSTRING(CREATE_DATE, 1, 8) >= #{beginTime}


    AND #{endTime} >= SUBSTRING(CREATE_DATE, 1, 8)


GROUP BY SUBSTRING(CREATE_DATE, 1, 8)

DECLARE @datePart CHAR(6) = SUBSTRING(CONVERT(CHAR(8), GETDATE(), 112), 3, 6);
DECLARE @maxSequence INT;
SELECT @maxSequence = MAX(CAST(SUBSTRING(TD002, 7, 5) AS INT))
FROM SFCTD
WHERE TD002 LIKE @datePart + '%'
  AND TD001 = #{TD001};
SET @maxSequence = ISNULL(@maxSequence, 0);
DECLARE @newSequence INT = @maxSequence + 1;
SELECT @datePart + RIGHT('00000' + CAST(@newSequence AS VARCHAR(5)), 5)
